BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?extSys ?extName ?role WHERE {
  ?aps rdf:type vocab:block ;
       vocab:NamedElement_name ?apsName .
  FILTER(CONTAINS(LCASE(STR(?apsName)), LCASE("aps mission")))

  {
    ?dep rdf:type vocab:dependency .
    ?dep vocab:Dependency_client ?aps ;
         vocab:Dependency_supplier ?extSys .
    BIND("client" AS ?role)
  }
  UNION
  {
    ?dep rdf:type vocab:dependency .
    ?dep vocab:Dependency_supplier ?aps ;
         vocab:Dependency_client ?extSys .
    BIND("supplier" AS ?role)
  }

  OPTIONAL { ?extSys vocab:NamedElement_name ?extName . }
}
ORDER BY ?role ?extName
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?apsName ?neighbor ?neighborName ?linkType WHERE {
  ?aps rdf:type vocab:block ;
       vocab:NamedElement_name ?apsName .
  FILTER(CONTAINS(LCASE(STR(?apsName)), LCASE("aps mission")))

  # Case 1: connector owned by the APS block (StructuredClassifier_ownedConnector)
  OPTIONAL {
    ?aps vocab:StructuredClassifier_ownedConnector ?connector .
    ?connector rdf:type vocab:connector .
    ?connector vocab:Connector_end ?end1 .
    ?end1 vocab:ConnectorEnd_role ?port1 .
    ?connector vocab:Connector_end ?end2 .
    ?end2 vocab:ConnectorEnd_role ?port2 .
    FILTER(?port1 != ?port2)

    # pick one end as the external neighbor port's owning element/classifier
    OPTIONAL { ?port1 vocab:NamedElement_name ?p1Name . }
    OPTIONAL { ?port2 vocab:NamedElement_name ?p2Name . }

    # Use both ports as candidates; label linkType
    BIND("port" AS ?linkType)
    BIND(STRAFTER(STR(?port1), "#") AS ?neighbor)
  }

  # Fallback: connectors via general connector-end incidence around ports used by APS
  OPTIONAL {
    ?connector rdf:type vocab:connector ;
               vocab:Connector_end ?end .
    ?end vocab:ConnectorEnd_role ?port .
    ?port vocab:NamedElement_name ?portName .
    FILTER(CONTAINS(LCASE(STR(?portName)), LCASE(STR(?apsName))))
    BIND("matched" AS ?linkType)
    BIND(?port AS ?neighbor)
    OPTIONAL { ?port vocab:NamedElement_name ?neighborName . }
  }

  # Derive neighbor name when possible
  OPTIONAL { ?neighbor vocab:NamedElement_name ?neighborName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?connector ?connName ?endPort ?endPortName WHERE {
  BIND(<http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control%20Alignment%20and%20Phasing%20System%20Systems%20Engineering::01%20Components%20Operational::Mission::APS%20Mission> AS ?aps)

  ?aps vocab:StructuredClassifier_ownedConnector ?connector .
  ?connector rdf:type vocab:connector .
  OPTIONAL { ?connector vocab:NamedElement_name ?connName . }

  ?connector vocab:Connector_end ?end .
  ?end vocab:ConnectorEnd_role ?endPort .
  OPTIONAL { ?endPort vocab:NamedElement_name ?endPortName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?apsName ?port ?portName ?connectedEndRole ?connectedPortName WHERE {
  ?aps rdf:type vocab:block ;
       vocab:NamedElement_name ?apsName .
  FILTER(CONTAINS(LCASE(STR(?apsName)), LCASE("aps mission")))

  # Find ports owned by/related to APS (encapsulated classifier ports)
  OPTIONAL { ?aps vocab:EncapsulatedClassifier_ownedPort ?port . }
  OPTIONAL { ?aps vocab:EncapsulatedClassifier_ownedPort ?port . }
  OPTIONAL { ?aps vocab:ownedPort ?port . }
  OPTIONAL { ?port rdf:type vocab:port . }

  ?connector rdf:type vocab:connector ;
             vocab:Connector_end ?e1, ?e2 .
  ?e1 vocab:ConnectorEnd_role ?port .
  ?e2 vocab:ConnectorEnd_role ?connectedEndRole .

  OPTIONAL { ?port vocab:NamedElement_name ?portName . }
  OPTIONAL { ?connectedEndRole vocab:NamedElement_name ?connectedPortName . }
}
LIMIT 25
